SELECT COUNT(*) FROM post

    deleted = 0

        AND topic_id = #{topicId}


        AND user_id = #{userId}


        AND status = #{status}


        AND (title LIKE CONCAT('%', #{keyword}, '%') OR content LIKE CONCAT('%', #{keyword}, '%'))

SELECT p.id, p.user_id, p.topic_id, p.title, p.content, p.images, p.like_count, p.comment_count, p.collect_count, p.view_count, p.status, p.is_top, p.is_essence, p.create_time, u.username, u.avatar as user_avatar, u.nickname as user_nickname, t.name as topic_name FROM post p LEFT JOIN user u ON p.user_id = u.id LEFT JOIN topic t ON p.topic_id = t.id WHERE p.deleted = 0
AND p.topic_id = #{topicId}
AND p.user_id = #{userId}
AND p.status = #{status}
AND (p.title LIKE CONCAT('%', #{keyword}, '%') OR p.content LIKE CONCAT('%', #{keyword}, '%'))
ORDER BY p.is_top DESC, p.create_time DESC LIMIT #{pageSize} OFFSET #{offset}
